import React, { useEffect, useState } from "react";
import Header from "./Header";
import NotFound from "./NotFound";
import { Route, Switch } from "react-router-dom";
import Decks from "./Decks";
import CreateDeckBtn from "./CreateDeckBtn";
import { listDecks, listCards } from "../utils/api/index.js";

function Layout() {
  const [decks, setDecks] = useState([]);
  const [cards, setCards] = useState([]);

  // LOAD DECKS
  useEffect(() => {
    async function loadDecks() {
      try {
        const deckData = await listDecks();
        deckData.forEach(item => {
          setDecks(decks => [...decks, {
            id: item.id,
            name: item.name,
            description: item.description
          }])
        })
      } catch (err) {
        console.log(err);
      }
    }
    loadDecks();
  }, []);

  // LOAD CARDS
  useEffect(() => {
    async function loadCards() {
      try {
        const data = await listCards();
        console.log("data cards: ", data)
        data.forEach(item => {
          setCards(cards => [...cards, {
            id: item.id,
            front: item.front,
            back: item.back,
            deckId: item.deckId
          }])
        })
      } catch (err) {
        console.log(err);
      }
    }
    loadCards();
  }, []);

  // RETURN LAYOUT
  return (
    <>
      <Header />
      <div className="container">
        <Switch>
          <Route exact path="/">
            <CreateDeckBtn />
            <Decks decks={decks} cards={cards} />
          </Route>
          <Route>
            <NotFound />
          </Route>
        </Switch>
      </div>
    </>
  );
}

export default Layout;
